      const auto res = sqlgen::exec(conn, "SELECT 1 FROM pragma_table_info('Course') WHERE name='CID' AND pk=1;");
      ASSERT_TRUE(res);
    }

    // Check Composite Primary Key in Score (SNo and CID both pk > 0)
