 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Define column references
    auto title_col = "title"_c;
    auto year_col = "year"_c;
    auto genre_col = "genre"_c;
    auto price_col = "price"_c;

    // Build the base query
    auto query = sqlgen::select_from<Book>("book_id"_c, "title"_c, "author"_c, 
                                         "year"_c, "genre"_c, "price"_c);

    // Build WHERE conditions dynamically
    auto conditions = std::vector<dynamic::Condition>();

    if (filters.title_keyword) {
        conditions.push_back(title_col.like("%" + *filters.title_keyword + "%"));
    }

    if (filters.min_year) {
        conditions.push_back(year_col >= *filters.min_year);
    }

    if (filters.genre) {
        conditions.push_back(genre_col == *filters.genre);
    }

    if (filters.max_price) {
        conditions.push_back(price_col <= *filters.max_price);
    }

    // Apply WHERE clause if any conditions were added
    if (!conditions.empty()) {
        auto combined_condition = conditions[0];
        for (size_t i = 1; i < conditions.size(); ++i) {
            combined_condition = combined_condition && conditions[i];
        }

        query = query | sqlgen::where(combined_condition);
    }

    // Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query execution failed");
    }

    return result.value();
