  Product p2{.product_id = 2, .name = "Widget B", .price = 20.0, .stock = 100};
  insert(conn, std::vector{p1, p2});

  Sale s1{.sale_id = 1, .product_id = 1, .quantity = 2, .amount = 20.0};
