  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return {};
  auto conn = conn_res.value();

  create_table<User>(conn);
  create_table<Post>(conn);

  const auto query =
      select_from<User, "u">(
          col<"user_id", "u"> | as<"user_id">,
          col<"name", "u"> | as<"name">,
          count() | as<"post_count">,
          avg(length(col<"content", "p">)) | as<"avg_length">) |
      left_join<Post, "p">(col<"user_id", "u"> == col<"user_id", "p">) |
      group_by(col<"user_id", "u">, col<"name", "u">) |
      to<std::vector<Stats>>;

  return query(conn).value();
}

