#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Build the SELECT query on Source table with WHERE condition
    auto select_query = sqlgen::select_from<Source>("value"_c) 
                      | sqlgen::where("value"_c > 100);

    // Create Target table from the select query
    return sqlgen::create_as<Target>(select_query);
}

}  // namespace create_table_as_select
```

## Explanation:

1. **`sqlgen::select_from<Source>("value"_c)`**: Starts building a SELECT query on the `Source` table, selecting only the `value` column using the string literal operator `_c`.

2. **`| sqlgen::where("value"_c > 100)`**: Applies the WHERE condition using the pipe operator `|` to filter records where `value > 100`.

3. **`sqlgen::create_as<Target>(select_query)`**: Creates a `Target` table from the constructed SELECT query.

4. **Return value**: The function returns the query object that can be executed against a database connection or converted to SQL using `sqlgen::sqlite::to_sql()`.

